// Comparar Facturas Pendientes vs Comprobantes de Pago en SharePoint
// Este nodo recibe las facturas pendientes de Excel y los archivos de SharePoint,
// y determina cuáles facturas ya tienen comprobante de pago.

const facturasPendientes = $('Excel - Leer Facturas Pendientes').all();
const archivosSharePoint = $('SharePoint - Verificar Pagos').all();

// Extraer nombres de archivos de comprobantes de pago
const nombresArchivos = archivosSharePoint.map(item => {
  const nombre = (item.json.name || item.json.fileName || '').toLowerCase();
  return nombre;
});

const resultados = [];

for (const factura of facturasPendientes) {
  const numeroFactura = (factura.json.numero_factura || '').toString().toLowerCase().trim();
  const proveedor = (factura.json.proveedor || '').toString().toLowerCase().trim();

  // Buscar si existe un comprobante de pago que coincida con el número de factura
  // Se busca por número de factura en el nombre del archivo
  const comprobanteEncontrado = nombresArchivos.some(archivo => {
    // Verificar si el nombre del archivo contiene el número de factura
    const contieneNumero = archivo.includes(numeroFactura);
    // Verificar si contiene palabras clave de pago
    const esPago = archivo.includes('pago') ||
                   archivo.includes('comprobante') ||
                   archivo.includes('recibo') ||
                   archivo.includes('transferencia') ||
                   archivo.includes('consignacion');
    return contieneNumero && esPago;
  });

  resultados.push({
    json: {
      numero_factura: factura.json.numero_factura,
      proveedor: factura.json.proveedor,
      monto_total: factura.json.monto_total,
      fecha_vencimiento: factura.json.fecha_vencimiento,
      estado_actual: factura.json.estado,
      pagada: comprobanteEncontrado,
      fecha_verificacion: new Date().toISOString(),
      // Preservar el índice de fila para poder actualizar en Excel
      row_index: factura.json.row_index || factura.json.__rowIndex || null
    }
  });
}

// Si no hay facturas pendientes, retornar un mensaje informativo
if (resultados.length === 0) {
  return [{
    json: {
      mensaje: 'No hay facturas pendientes para verificar',
      pagada: false,
      fecha_verificacion: new Date().toISOString()
    }
  }];
}

return resultados;

// Calcular Métricas del Dashboard de Facturación
// Este nodo procesa el histórico completo de facturas y genera métricas
// para los últimos 3 meses: totales, promedios, desglose por proveedor y comparaciones.

const todasLasFacturas = $input.all();
const hoy = new Date();

// Obtener los últimos 3 meses en formato YYYY-MM
const obtenerUltimos3Meses = () => {
  const meses = [];
  for (let i = 0; i < 3; i++) {
    const fecha = new Date(hoy.getFullYear(), hoy.getMonth() - i, 1);
    const mes = fecha.toISOString().slice(0, 7);
    meses.push(mes);
  }
  return meses;
};

const mesesAnalisis = obtenerUltimos3Meses();
const nombresMeses = {
  '01': 'Enero', '02': 'Febrero', '03': 'Marzo', '04': 'Abril',
  '05': 'Mayo', '06': 'Junio', '07': 'Julio', '08': 'Agosto',
  '09': 'Septiembre', '10': 'Octubre', '11': 'Noviembre', '12': 'Diciembre'
};

// Inicializar estructura de datos por mes
const datosPorMes = {};
mesesAnalisis.forEach(mes => {
  datosPorMes[mes] = {
    facturas: [],
    totalFacturado: 0,
    cantidadFacturas: 0,
    promedioPorFactura: 0,
    proveedores: {},
    pendientes: 0,
    pagadas: 0,
    totalIVA: 0
  };
});

// Procesar cada factura
for (const item of todasLasFacturas) {
  const factura = item.json;
  const mesFactura = (factura.mes || factura.fecha_emision || '').toString().slice(0, 7);

  if (datosPorMes[mesFactura]) {
    const monto = parseFloat(factura.monto_total) || 0;
    const iva = parseFloat(factura.iva) || 0;
    const proveedor = factura.proveedor || 'Sin proveedor';
    const estado = (factura.estado || '').toString().toLowerCase();

    datosPorMes[mesFactura].facturas.push(factura);
    datosPorMes[mesFactura].totalFacturado += monto;
    datosPorMes[mesFactura].cantidadFacturas += 1;
    datosPorMes[mesFactura].totalIVA += iva;

    // Desglose por proveedor
    if (!datosPorMes[mesFactura].proveedores[proveedor]) {
      datosPorMes[mesFactura].proveedores[proveedor] = {
        total: 0,
        cantidad: 0
      };
    }
    datosPorMes[mesFactura].proveedores[proveedor].total += monto;
    datosPorMes[mesFactura].proveedores[proveedor].cantidad += 1;

    // Conteo por estado
    if (estado === 'pagada' || estado === 'pagado') {
      datosPorMes[mesFactura].pagadas += 1;
    } else {
      datosPorMes[mesFactura].pendientes += 1;
    }
  }
}

// Calcular promedios
for (const mes of mesesAnalisis) {
  const datos = datosPorMes[mes];
  datos.promedioPorFactura = datos.cantidadFacturas > 0
    ? Math.round(datos.totalFacturado / datos.cantidadFacturas)
    : 0;
  datos.totalFacturado = Math.round(datos.totalFacturado);
  datos.totalIVA = Math.round(datos.totalIVA);
}

// Calcular comparaciones porcentuales mes a mes
const comparaciones = [];
for (let i = 0; i < mesesAnalisis.length - 1; i++) {
  const mesActual = mesesAnalisis[i];
  const mesAnterior = mesesAnalisis[i + 1];
  const totalActual = datosPorMes[mesActual].totalFacturado;
  const totalAnterior = datosPorMes[mesAnterior].totalFacturado;

  let variacionPorcentual = 0;
  if (totalAnterior > 0) {
    variacionPorcentual = Math.round(((totalActual - totalAnterior) / totalAnterior) * 10000) / 100;
  }

  comparaciones.push({
    mes_actual: mesActual,
    mes_anterior: mesAnterior,
    variacion_porcentual: variacionPorcentual,
    diferencia_absoluta: totalActual - totalAnterior,
    tendencia: variacionPorcentual > 0 ? 'AUMENTO' : variacionPorcentual < 0 ? 'DISMINUCION' : 'ESTABLE'
  });
}

// Contar totales globales de pendientes y pagadas
let totalPendientesGlobal = 0;
let totalPagadasGlobal = 0;
let montoPendienteGlobal = 0;

for (const item of todasLasFacturas) {
  const factura = item.json;
  const estado = (factura.estado || '').toString().toLowerCase();
  if (estado === 'pagada' || estado === 'pagado') {
    totalPagadasGlobal += 1;
  } else {
    totalPendientesGlobal += 1;
    montoPendienteGlobal += parseFloat(factura.monto_total) || 0;
  }
}

// Construir desglose por proveedor para cada mes
const desglosePorMes = {};
for (const mes of mesesAnalisis) {
  const partesMes = mes.split('-');
  const nombreMes = nombresMeses[partesMes[1]] + ' ' + partesMes[0];
  desglosePorMes[nombreMes] = {
    total_facturado: datosPorMes[mes].totalFacturado,
    cantidad_facturas: datosPorMes[mes].cantidadFacturas,
    promedio_por_factura: datosPorMes[mes].promedioPorFactura,
    total_iva: datosPorMes[mes].totalIVA,
    pendientes: datosPorMes[mes].pendientes,
    pagadas: datosPorMes[mes].pagadas,
    proveedores: Object.entries(datosPorMes[mes].proveedores).map(([nombre, datos]) => ({
      nombre,
      total: Math.round(datos.total),
      cantidad: datos.cantidad,
      porcentaje_del_total: datosPorMes[mes].totalFacturado > 0
        ? Math.round((datos.total / datosPorMes[mes].totalFacturado) * 10000) / 100
        : 0
    })).sort((a, b) => b.total - a.total)
  };
}

// Resultado final del dashboard
return {
  json: {
    dashboard_generado: new Date().toISOString(),
    periodo_analisis: {
      desde: mesesAnalisis[mesesAnalisis.length - 1],
      hasta: mesesAnalisis[0]
    },
    resumen_global: {
      total_facturas: todasLasFacturas.length,
      facturas_pendientes: totalPendientesGlobal,
      facturas_pagadas: totalPagadasGlobal,
      monto_pendiente_total: Math.round(montoPendienteGlobal),
      porcentaje_pagado: todasLasFacturas.length > 0
        ? Math.round((totalPagadasGlobal / todasLasFacturas.length) * 10000) / 100
        : 0
    },
    metricas_por_mes: desglosePorMes,
    comparaciones_mes_a_mes: comparaciones
  }
};
